class Solution {
public:
    int longestSubsequence(string s, int k) {
        int count = 0;
        for (char c : s) {
            if (c == '0') {
                count++;
            }
        }
        string bin_k = "";
        while (k > 0) {
            bin_k = (k % 2 == 0 ? "0" : "1") + bin_k;
            k /= 2;
        }
        int i = s.size() - 1, j = bin_k.size() - 1;
        while (i >= 0 && j >= 0) {
            if (s[i] == bin_k[j]) {
                count++;
                j--;
            }
            i--;
        }
        return count;
    }
};
```
efficiency: HIGH
time complexity: O(n + log k)
space complexity: O(log k)
